#!/usr/bin/perl -w
use strict;
print "Content-Type: text/html\n\n";  # start of headers section, content type html must be first line in perls cgi scripts for it to work properly. It's not necessary but should always come before any output data or the end script tag (in this case). next part is body
use CGI;   # Perl module that handles GET and POST parameters from a form submission, including file upload fields – useful if you have an HTML page with input for posting comments. If not using get/post method then no need to use it here as we are only reading data in the script itself (not handling post request).
use CGI qw(:standard);   # provides standard functions like $query_string,$POST and others that you can directly call on them such as: print "Value of param is : ",  $QUERY_PAGE; or for form parameters use cgi()->param('mytext');. 
use CGI qw(:output_headers); #CGI module to output headers in Perl script, useful if you want your server response be sent as a HTTP Response (not HTML) and not just print the data on browser console but this is needed for perls cgi scripts when we are handling post request.
use CGI qw(:dbi);  #provides methods like db_connect(), query() etc to connect with database using DBI module, you can use it if your requirement includes dealing of databases in the script as well (not required here).
my $cgi = CGI->new;   # instantiate a new cgi object. 
print "<div>$comment</div><br /> <a href='/board' >Back to discussion board <\a/\n";    # print the comment and back button link (you need HTML formatting here) in HTTP response body, no markdown needed for this part as it is a simple text.